-- ============================================================================
-- 创建20个教学用设备
-- 文件: 23_create_teaching_devices.sql
-- 日期: 2025-11-27
-- 说明: 为教学活动预先注册20个设备，配置相同的传感器和预设指令
--       UUID使用MySQL内置UUID()函数自动生成
-- ============================================================================

-- 注意：
-- 1. 本脚本使用MySQL的UUID()函数自动生成设备UUID
-- 2. 执行后请查询数据库获取实际生成的UUID
-- 3. 将生成的UUID分配给学生使用

-- 查看生成的设备UUID：
-- SELECT name, uuid, device_id, mac_address FROM aiot_core_devices WHERE name LIKE '教学设备%' ORDER BY name;

INSERT INTO `aiot_core_devices` (
    `uuid`, `device_id`, `product_id`, `user_id`, `name`, `description`, 
    `device_secret`, `firmware_version`, `hardware_version`, `device_status`, 
    `is_online`, `is_active`, `mac_address`, 
    `device_sensor_config`, `device_control_config`, `device_settings`, 
    `quality_grade`, `error_count`, `uptime`, `product_switch_count`, `auto_created_product`,
    `created_at`, `updated_at`
) VALUES

