-- ============================================================================
-- 验证和导出查询
-- ============================================================================

-- 1. 查看生成的设备UUID（执行插入后运行）
SELECT 
    SUBSTRING(name, 5) as '设备编号',
    uuid as 'UUID',
    device_id as 'Device ID',
    device_secret as 'Device Secret',
    mac_address as 'MAC地址'
FROM aiot_core_devices 
WHERE name LIKE '教学设备%' 
ORDER BY name;

-- 2. 导出为CSV格式（可复制结果）
SELECT 
    SUBSTRING(name, 5) as '设备编号',
    uuid,
    device_id,
    device_secret,
    mac_address
FROM aiot_core_devices 
WHERE name LIKE '教学设备%' 
ORDER BY name;

-- 3. 仅查看UUID列表（供学生使用）
SELECT 
    name as '设备名称',
    uuid as '设备UUID'
FROM aiot_core_devices 
WHERE name LIKE '教学设备%' 
ORDER BY name;

